SELECT res_id , com_id , res_code , res_name , res_type , quantity , remark , created_at , updated_at FROM resource WHERE com_id = #{comId}
AND (res_name LIKE CONCAT('%', #{keyword}, '%') OR res_code LIKE CONCAT('%', #{keyword}, '%'))
AND res_type = #{resType}
ORDER BY res_id DESC LIMIT #{pstartno}, #{onepagelist}

SELECT COUNT(*)
FROM resource
WHERE com_id = #{comId}
